1	const forwardDelta: Record<string, { dx: number; dy: number }> = {
2	  N: { dx: 0, dy: 1 },
3	  E: { dx: 1, dy: 0 },
4	  S: { dx: 0, dy: -1 },
5	  W: { dx: -1, dy: 0 },
6	};
7	
8	export function moveRover(rover: { x: number; y: number; heading: string }, commands: string) {
9	  const delta = commands === "F" ? forwardDelta[rover.heading] : undefined;
10	  return delta ? { ...rover, x: rover.x + delta.dx, y: rover.y + delta.dy } : rover;
11	}
